-- 4.2.3 Группа методической поддержки
WITH ins AS (
  INSERT INTO t_p61016064_digital_innovation_i.dept_functions (project_id, dept_name, title, category, source_section_code)
  SELECT 1, 'Департамент финансового мониторинга (ДФМ)', v.title, v.category, '4.2.3'
  FROM (VALUES
    ('Разработка методических материалов (инструкции, памятки и др.) в рамках функционала Управления обязательного контроля и отчётности по применению и использованию новых реализованных процедур обязательного контроля','methodology'),
    ('Инициирование доработки специализированных программных комплексов Банка в связи с изменениями законодательства Российской Федерации в сфере ПОД/ФТ в части, касающейся деятельности Группы методической поддержки','operational'),
    ('Осуществление выборочного контроля полноты и своевременности формирования сведений, направляемых в Уполномоченный орган','control'),
    ('Осуществление консультирования работников Управления обязательного контроля и отчётности и УФМ СЦ по вопросам выявления, квалификации операций, подлежащих обязательному контролю, в целях обеспечения неукоснительного соблюдения ими требований законодательства Российской Федерации и нормативных актов Банка России в сфере ПОД/ФТ','communication')
  ) AS v(title, category)
  RETURNING id, source_section_code
)
INSERT INTO t_p61016064_digital_innovation_i.function_org_units (function_id, org_unit_id, role, source_ref)
SELECT ins.id, u.id, 'owner', 'polozhenie'
FROM ins JOIN t_p61016064_digital_innovation_i.org_units u
  ON u.project_id = 1 AND u.code = '4.2.3' AND u.is_archived = false;

-- 4.3 Управление противодействия подозрительным операциям
WITH ins2 AS (
  INSERT INTO t_p61016064_digital_innovation_i.dept_functions (project_id, dept_name, title, category, source_section_code)
  SELECT 1, 'Департамент финансового мониторинга (ДФМ)', v.title, v.category, '4.3'
  FROM (VALUES
    ('Осуществление контроля соблюдения Филиалами Банка ПВК по ПОД/ФТ и программ их осуществления в рамках вопросов, относящихся к функционалу Управления противодействия подозрительным операциям','control'),
    ('Осуществление консультирования работников Банка по вопросам, находящимся в компетенции Управления противодействия подозрительным операциям','communication'),
    ('Выявление новых типов и видов сомнительных финансовых схем, направленных на легализацию преступных доходов или финансирование терроризма','analytical'),
    ('Разработка ПВК по ПОД/ФТ и программ их осуществления в части, касающейся деятельности Управления противодействия подозрительным операциям','methodology'),
    ('Консультирование работников профильных структурных подразделений Банка по вопросам, возникающим при реализации ПВК по ПОД/ФТ по функционалу Управления противодействия подозрительным операциям, в том числе в рамках выявления необычных операций (сделок), выявлении совокупности подозрительных операций и (или) действий при осуществлении Банком профессиональной деятельности на рынке ценных бумаг','communication'),
    ('Разработка технических заданий для реализации Управлением систем комплаенс-контроля и управления рисками Департамента развития общебанковских систем по вопросам, входящим в компетенцию Управления противодействия подозрительным операциям','methodology')
  ) AS v(title, category)
  RETURNING id, source_section_code
)
INSERT INTO t_p61016064_digital_innovation_i.function_org_units (function_id, org_unit_id, role, source_ref)
SELECT ins2.id, u.id, 'owner', 'polozhenie'
FROM ins2 JOIN t_p61016064_digital_innovation_i.org_units u
  ON u.project_id = 1 AND u.code = '4.3' AND u.is_archived = false;